// core/guards/admin-auth.guard.ts
import { inject } from '@angular/core';
import { CanActivateFn, Router } from '@angular/router';
import { OidcSecurityService } from 'angular-auth-oidc-client';
import { firstValueFrom } from 'rxjs';

export const adminAuthGuard: CanActivateFn = async () => {
  const oidcService = inject(OidcSecurityService);
  const router = inject(Router);

  try {
    const { isAuthenticated } = await firstValueFrom(oidcService.isAuthenticated$);
    if (isAuthenticated) return true;

    // Trigger OIDC login flow — redirects to /connect/authorize
    oidcService.authorize();
    return false;
  } catch {
    // OIDC discovery or configuration error
    return router.createUrlTree(['/login'], {
      queryParams: { error: 'oidc_unavailable' },
    });
  }
};

@Component({
  selector: 'app-admin-shell',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, AppShellComponent],
  templateUrl: './admin-shell.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AdminShellComponent {
  navItems: NavItem[] = [
    { label: 'nav.actions', path: '/admin/actions', icon: 'clipboard-check' },
    { label: 'nav.workflows', path: '/admin/workflows', icon: 'diagram-3' },
    { label: 'nav.complianceProfiles', path: '/admin/compliance-profiles', icon: 'shield-check' },
    { label: 'nav.escalationRules', path: '/admin/escalation-rules', icon: 'arrow-up-circle' },
    // ... all admin sections — labels are translate keys
  ];
}

// Add: navigate to /new
onCreateAction(): void {
  this.router.navigate(['/admin/actions/new']);
}

// Edit: navigate to /:id (single-select or double-click)
onEdit(): void {
  const selected = this.selectedItems();
  if (selected.length === 1) {
    this.router.navigate(['/admin/actions', selected[0].id]);
  }
}

onRowDoubleClicked(event: RowDoubleClickedEvent<ActionGridItemDTO>): void {
  if (event.data) {
    this.router.navigate(['/admin/actions', event.data.id]);
  }
}

// Cancel navigates back to list
onCancel(): void {
  this.router.navigate(['/admin/workflows']);
}

// Save in create mode: redirect to edit route for the new entity
async onSave(): Promise<void> {
  const result = await this.workflowService.save(request);
  if (this.isEditMode()) {
    await this.loadWorkflow(this.id()!);  // Reload in place
  } else {
    this.router.navigate(['/admin/workflows', result.id]);  // Redirect to edit
  }
}

